import React, { useState, useCallback } from "react";
import axios from "axios";
import "./App.css";
import IndividualAnalysis from "./IndividualAnalysis";
import BatchAnalysis from "./BatchAnalysis";

const API_BASE = "http://localhost:5000/api";

// Default customer data for reset functionality
const DEFAULT_CUSTOMER_DATA = {
  Tenure: 5.0,
  OrderCount: 5.0,
  CashbackAmount: 12000.0,
  DaySinceLastOrder: 7.0,
  HourSpendOnApp: 30.0,
  OrderAmountHikeFromlastYear: 15.0,
  CouponUsed: 1,
  NumberOfDeviceRegistered: 3,
  Complain: 0,
  SatisfactionScore: 3,
  WarehouseToHome: 10.0,
  NumberOfAddress: 4,
  CityTier: 1,
  PreferredLoginDevice: "Mobile Phone",
  PreferredPaymentMode: "Credit Card",
  PreferedOrderCat: "Laptop & Accessory",
  Gender: "Male",
  MaritalStatus: "Married",
};

function App() {
  const [mode, setMode] = useState("individual");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [results, setResults] = useState(null);
  const [batchResults, setBatchResults] = useState(null);
  const [batchFile, setBatchFile] = useState(null);
  const [customerData, setCustomerData] = useState(DEFAULT_CUSTOMER_DATA);

  // Clear all results and errors when switching modes
  const handleModeChange = useCallback((newMode) => {
    setMode(newMode);
    setResults(null);
    setBatchResults(null);
    setError(null);
  }, []);

  // Reset form to default values
  const handleResetForm = useCallback(() => {
    setCustomerData(DEFAULT_CUSTOMER_DATA);
    setResults(null);
    setError(null);
  }, []);

  const handleIndividualAnalyze = async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await axios.post(`${API_BASE}/individual`, customerData);
      setResults(res.data);
    } catch (err) {
      const errorMessage = err.response?.data?.message || "Failed to analyze customer data";
      setError(errorMessage);
      console.error("Analysis error:", err);
    } finally {
      setLoading(false);
    }
  };

  const handleBatchAnalyze = async () => {
    if (!batchFile) {
      setError("Please select a file first");
      return;
    }

    setLoading(true);
    setError(null);
    const formData = new FormData();
    formData.append("file", batchFile);

    try {
      const res = await axios.post(`${API_BASE}/batch`, formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
        timeout: 30000, // 30 second timeout for batch processing
      });
      setBatchResults(res.data);
    } catch (err) {
      const errorMessage = err.response?.data?.message || "Failed to process batch file";
      setError(errorMessage);
      console.error("Batch analysis error:", err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="app-wrapper">
      <header className="top-header">
        <h1 className="project-title">
          Customer <span>Churn Intelligence</span>
        </h1>

        <div className="mode-toggle">
          <button
            className={`mode-btn ${mode === "individual" ? "active" : ""}`}
            onClick={() => handleModeChange("individual")}
          >
            📊 Individual Analysis
          </button>
          <button
            className={`mode-btn ${mode === "batch" ? "active" : ""}`}
            onClick={() => handleModeChange("batch")}
          >
            📁 Batch Analysis
          </button>
        </div>

        <p className="mode-description">
          {mode === "individual"
            ? "Analyze churn probability for individual customers with detailed insights"
            : "Process multiple customers at once with CSV file upload"}
        </p>
      </header>

      <main className="dashboard futuristic-bg">
        {/* Error Display */}
        {error && (
          <div className="error-banner">
            <span>⚠️ {error}</span>
            <button onClick={() => setError(null)} className="close-error">×</button>
          </div>
        )}

        {mode === "individual" ? (
          <IndividualAnalysis
            customerData={customerData}
            onInputChange={setCustomerData}
            onAnalyze={handleIndividualAnalyze}
            onReset={handleResetForm}
            loading={loading}
            results={results}
            error={error}
          />
        ) : (
          <BatchAnalysis
            onFileChange={(e) => {
              setBatchFile(e.target.files[0]);
              setError(null);
            }}
            onAnalyze={handleBatchAnalyze}
            loading={loading}
            results={batchResults}
            selectedFile={batchFile}
          />
        )}
      </main>
    </div>
  );
}

export default App;
